/*AdminMng_SQL.selectMenuNmDupliChk*/
SELECT COUNT(*)
  FROM TB_ADMIN_MENU_INFO
WHERE 1=1
    AND MENU_NM = #{uniqueKey}
    AND MENU_DEL_YN = 'N'

/*AdminMng_SQL.selectCommGroupCdDupliChk*/
SELECT COUNT(*)
  FROM TB_COMMON_INFO
WHERE 1=1
    AND COMM_GROUP_CD = #{uniqueKey}
    AND COMM_DEL_YN = 'N'

/*AdminMng_SQL.selectUnitCdDupliChk*/
SELECT COUNT(*)
  FROM TB_ADMIN_UNIT_INFO
WHERE 1=1
    AND ADMIN_UNIT_CD = #{uniqueKey}
    AND ADMIN_UNIT_DEL_YN = 'N'

/*AdminMng_SQL.selectAdminIdDupliChk*/
SELECT COUNT(*)
  FROM TB_ADMIN_INFO
WHERE 1=1
    AND ADMIN_ID = #{uniqueKey}
    AND ADMIN_DEL_YN = 'N'

mapper.insert:
/*AdminMng_SQL.adminCommReg*/
INSERT INTO TB_ADMIN_MENU_FAVORITE (
	  MENU_FAVORITE_ID
	, MENU_FAVORITE_ADMIN_ID
	, MENU_FAVORITE_URL
	, MENU_FAVORITE_NM
	, REG_ID
	, REG_DT
	, UPD_ID
	, UPD_DT
) VALUES (
	  (SELECT FN_GET_UNIQUE_KEY())
	, #{menuFavoriteAdminId}
	, #{menuFavoriteUrl}
	, #{menuFavoriteNm}
	, #{regId}
	, NOW()
	, #{updId}
	, NOW()
);

mapper.delete:
DELECT FROM TB_ADMIN_MENU_FAVORITE
WHERE 1=1 
    AND MENU_FAVORITE_ID = #{menuFavoriteId}
    AND MENU_FAVORITE_ID = #{menuFavoriteAdminId}
